-- 90/90 Hip Switch with Reach (9090-hip-switch-with-reach)
UPDATE coaching.exercise SET
  name = '90/90 Hip Switch with Reach',
  description = 'Perform 90/90 Hip Switch with Reach slowly enough to create usable rotational access and coordination. Move through pain-free range, breathe, and own the position before adding speed or load.',
  card_summary = '90/90 Hip Switch with Reach is a Prepare & Access exercise for hip internal/external rotation and ribcage-pelvis organization. Use it when the goal is rotational skill, force transfer, or power quality rather than fatigue chasing.',
  coach_language = 'Primary subrole: mobilize. Coach 90/90 Hip Switch with Reach as rotational-athlete work: rotation should be organized through feet, hips, pelvis, thoracic spine, shoulders, and the implement or direction change - not forced through the low back.',
  athlete_language = 'Open the range, feel the turn, and do not force your low back.',
  movement_family = 'Hip rotation access',
  primary_phase_key = 'prepare_and_access',
  phase_subrole = 'mobilize',
  primary_order_slot = 'hip_rotation_9090_reach_access',
  default_sets = 2,
  default_reps = 6,
  default_work_seconds = 25,
  default_rest_seconds = 20,
  est_seconds_per_set = 45,
  movement_requirements = '{"primary_joint_actions":["hip rotation","thoracic rotation","trunk bracing"],"primary_tissues":["core","hip","spine"],"breathing_demand":"low_to_moderate","balance_demand":"moderate","coordination_demand":"moderate_to_high","impact_level":0,"rotational_power_profile":{"rotation_source":"feet, hips, pelvis, thoracic spine, and shoulders; avoid forced lumbar twisting","sequence_priority":"load or gather, brace, rotate, transfer, finish, and reset","quality_rule":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated."}}'::jsonb,
  coaching_execution = '{"movement_description":"Perform 90/90 Hip Switch with Reach slowly enough to create usable rotational access and coordination. Move through pain-free range, breathe, and own the position before adding speed or load.","setup":["Clear the training area and define the athlete''s start position, finish position, and stop command.","Coach one clean practice rep before adding load, speed, partner input, or decision demand."],"execution_steps":["Move into the starting position slowly and find the target joint or stance position.","Rotate, reach, shift, or step through pain-free range while breathing naturally.","Return with control and repeat only as long as the motion improves readiness without fatigue."],"coach_cues":["Rotate from the ground up.","Ribs and pelvis travel as a team.","Own the finish before the next rep.","Open range without forcing it.","Smooth first, then crisp."],"common_faults":["Low back becomes the main rotation point.","Feet lose pressure or the athlete spins on the toes without a controlled base.","Ribs flare, shoulders shrug, or pelvis dumps forward during the turn."],"breathing_cues":["Exhale through effort or release.","Do not hold breath to force rotation.","Recover breathing before the next high-intent rep."],"quality_gate":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated.","stop_signs":["Sharp pain, joint pinch, numbness, tingling, dizziness, or symptom increase.","Lumbar spine becomes the main source of rotation instead of hips, pelvis, thoracic spine, and shoulders.","The athlete loses foot pressure, trunk stack, safe landing, throw accuracy, or controlled reset."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Rotational power output","Rotational strength","Sport skill"],"pairs_well_after":["General warm-up","Breathing reset","Low-intensity locomotion"],"good_for_sessions":["rotational_power","rotational_athlete_prep","general_warmup","mobility_access"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete has pain, dizziness, neurological symptoms, or medical restrictions that make rotation unsafe.","The athlete cannot control basic stance, brace, or landing positions for the chosen variation.","The session has already created enough fatigue that rotation quality or decision quality is degraded."],"notes":null}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal demo needed: front, side, and rotation-angle view.","Use sport-coach review for throwing, hitting, swinging, or cutting transfer examples."],"internal_notes":["Film first set from front and side. Approve progression only when rotation source, finish, and reset are repeatable."]}'::jsonb,
  updated_at = now()
WHERE slug = '9090-hip-switch-with-reach';

