  card_summary = 'Landmine Rotation is a Capacity exercise for loaded hip-to-trunk rotational drive. Use it when the goal is rotational skill, force transfer, or power quality rather than fatigue chasing.',
  coach_language = 'Primary subrole: rotational_force_transfer_strength. Coach Landmine Rotation as rotational-athlete work: rotation should be organized through feet, hips, pelvis, thoracic spine, shoulders, and the implement or direction change - not forced through the low back.',
  athlete_language = 'Brace first, move the load through your hips and trunk, and keep every rep repeatable.',
  movement_family = 'Loaded rotational strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'rotational_force_transfer_strength',
  primary_order_slot = 'landmine_rotation_strength',
  default_sets = 3,
  default_reps = 6,
  default_work_seconds = 35,
  default_rest_seconds = 75,
  est_seconds_per_set = 110,
  movement_requirements = '{"primary_joint_actions":["hip rotation","thoracic rotation","trunk bracing"],"primary_tissues":["core","hip","shoulder","spine"],"breathing_demand":"moderate","balance_demand":"moderate","coordination_demand":"moderate_to_high","impact_level":1,"rotational_power_profile":{"rotation_source":"feet, hips, pelvis, thoracic spine, and shoulders; avoid forced lumbar twisting","sequence_priority":"load or gather, brace, rotate, transfer, finish, and reset","quality_rule":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated."}}'::jsonb,
  coaching_execution = '{"movement_description":"Perform Landmine Rotation as controlled loaded strength work. Use load, stance, and range that allow clean bracing, hip contribution, and repeatable rotational force transfer.","setup":["Clear the training area and define the athlete''s start position, finish position, and stop command.","Select a load the athlete can control without lumbar twisting, breath holding, or loss of stance.","Coach one clean practice rep before adding load, speed, partner input, or decision demand."],"execution_steps":["Set stance, grip, and rib-pelvis position before moving the load.","Move through the planned range while the hips and trunk share the rotational or diagonal force demand.","Return under control and stop the set before load path, brace, or posture changes."],"coach_cues":["Rotate from the ground up.","Ribs and pelvis travel as a team.","Own the finish before the next rep.","Load the hips, not the spine.","Control the return as much as the drive."],"common_faults":["Low back becomes the main rotation point.","Feet lose pressure or the athlete spins on the toes without a controlled base.","Ribs flare, shoulders shrug, or pelvis dumps forward during the turn.","Load is progressed before the athlete controls the rotational path."],"breathing_cues":["Exhale through effort or release.","Do not hold breath to force rotation.","Recover breathing before the next high-intent rep."],"quality_gate":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated.","stop_signs":["Sharp pain, joint pinch, numbness, tingling, dizziness, or symptom increase.","Lumbar spine becomes the main source of rotation instead of hips, pelvis, thoracic spine, and shoulders.","The athlete loses foot pressure, trunk stack, safe landing, throw accuracy, or controlled reset."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Resilience trunk/braking block","Sustained Capacity conditioning","Restore"],"pairs_well_after":["Rotational power block","Movement Intelligence sequencing drill","General warm-up"],"good_for_sessions":["rotational_power","rotational_athlete_prep","strength","force_tissue_capacity"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete has pain, dizziness, neurological symptoms, or medical restrictions that make rotation unsafe.","The athlete cannot control basic stance, brace, or landing positions for the chosen variation.","The session has already created enough fatigue that rotation quality or decision quality is degraded."],"notes":null}'::jsonb,
