-- Med Ball Slam to Rotational Throw (med-ball-slam-to-rotational-throw)
UPDATE coaching.exercise SET
  name = 'Med Ball Slam to Rotational Throw',
  description = 'Perform Med Ball Slam to Rotational Throw with a light-to-moderate medicine ball. Load the body through the feet and hips, rotate with a stacked trunk, release or catch cleanly, and reset before the next throw.',
  card_summary = 'Med Ball Slam to Rotational Throw is a Output exercise for absorb and re-output force rotationally. Use it when the goal is rotational skill, force transfer, or power quality rather than fatigue chasing.',
  coach_language = 'Primary subrole: jump_throw_explosive_power. Coach Med Ball Slam to Rotational Throw as rotational-athlete work: rotation should be organized through feet, hips, pelvis, thoracic spine, shoulders, and the implement or direction change - not forced through the low back.',
  athlete_language = 'Load clean, rotate fast, finish under control, then reset.',
  movement_family = 'Re-acceleration rotational power',
  primary_phase_key = 'output',
  phase_subrole = 'jump_throw_explosive_power',
  primary_order_slot = 'med_ball_slam_to_rotational_throw',
  default_sets = 3,
  default_reps = 4,
  default_work_seconds = 12,
  default_rest_seconds = 75,
  est_seconds_per_set = 90,
  movement_requirements = '{"primary_joint_actions":["hip rotation","shoulder horizontal adduction/rotation","thoracic rotation","trunk bracing","trunk-to-arm force transfer"],"primary_tissues":["ankle","core","hip","shoulder"],"breathing_demand":"low_to_moderate","balance_demand":"moderate_to_high","coordination_demand":"high","impact_level":1,"rotational_power_profile":{"rotation_source":"feet, hips, pelvis, thoracic spine, and shoulders; avoid forced lumbar twisting","sequence_priority":"load or gather, brace, rotate, transfer, finish, and reset","quality_rule":"The attempt counts only if speed or throw intent is high, the rotation is sequenced from the ground up, the landing/finish is controlled, and the athlete can reset without rushing."}}'::jsonb,
  coaching_execution = '{"movement_description":"Perform Med Ball Slam to Rotational Throw with a light-to-moderate medicine ball. Load the body through the feet and hips, rotate with a stacked trunk, release or catch cleanly, and reset before the next throw.","setup":["Clear the training area and define the athlete''s start position, finish position, and stop command.","Choose a medicine ball light enough to move fast without changing posture or release path.","Use a solid wall and stand far enough away that the ball rebound or release is safe.","Coach one clean practice rep before adding load, speed, partner input, or decision demand."],"execution_steps":["Start in the prescribed stance and create quiet tension through feet, hips, and trunk.","Load or reorient under control, then express the throw, jump, cut, or sprint with high intent.","Stick, catch, release, or finish cleanly; reset fully before the next attempt."],"coach_cues":["Rotate from the ground up.","Ribs and pelvis travel as a team.","Own the finish before the next rep.","Fast intent, low volume.","Throw or move through the target, not through your low back."],"common_faults":["Low back becomes the main rotation point.","Feet lose pressure or the athlete spins on the toes without a controlled base.","Ribs flare, shoulders shrug, or pelvis dumps forward during the turn.","Too many reps turn power into conditioning.","Throw or cut accuracy drops but the set continues anyway.","Ball is too heavy, making the throw slow or arm-dominant."],"breathing_cues":["Exhale through effort or release.","Do not hold breath to force rotation.","Recover breathing before the next high-intent rep."],"quality_gate":"The attempt counts only if speed or throw intent is high, the rotation is sequenced from the ground up, the landing/finish is controlled, and the athlete can reset without rushing.","stop_signs":["Sharp pain, joint pinch, numbness, tingling, dizziness, or symptom increase.","Lumbar spine becomes the main source of rotation instead of hips, pelvis, thoracic spine, and shoulders.","The athlete loses foot pressure, trunk stack, safe landing, throw accuracy, or controlled reset.","Throw speed, jump/contact quality, cut angle, or acceleration intent drops noticeably."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Capacity strength block","Sport skill block","Sustained Capacity conditioning"],"pairs_well_after":["General warm-up","Rotational access drill","Low-level sequencing primer"],"good_for_sessions":["rotational_power","rotational_athlete_prep","power_output","throwing_power","speed_agility"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["The athlete has pain, dizziness, neurological symptoms, or medical restrictions that make rotation unsafe.","The athlete cannot control basic stance, brace, or landing positions for the chosen variation.","The session has already created enough fatigue that rotation quality or decision quality is degraded."],"notes":null}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal demo needed: front, side, and rotation-angle view.","Use sport-coach review for throwing, hitting, swinging, or cutting transfer examples."],"internal_notes":["Film first set from front and side. Approve progression only when rotation source, finish, and reset are repeatable."]}'::jsonb,
  updated_at = now()
WHERE slug = 'med-ball-slam-to-rotational-throw';

