UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'pivot_to_sprint_start',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = TRUE,
  fatigue_sensitivity = 5,
  fatigue_cost = 5,
  technical_complexity = 4,
  impact_level = 1,
  intensity_ceiling = 'high',
  notes = ''
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'output'
JOIN coaching.phase_order_slot pos ON pos.key = 'pivot_to_sprint_start' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'pivot-to-sprint-start';

UPDATE coaching.exercise_dosage_profile d SET
  volume_unit = 'attempts',
  default_sets = 4,
  default_reps = 2,
  default_distance = NULL::integer,
  default_work_seconds = 8,
  default_rest_seconds = 90,
  est_seconds_per_set = 105,
  default_rpe_min = 7,
  default_rpe_max = 9,
  session_volume_min = NULL,
  session_volume_max = NULL
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'pivot-to-sprint-start';

UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = FALSE,
  weekly_max_frequency = 3,
  minimum_hours_between_hard_exposures = 24,
  counts_as_high_intensity = TRUE,
  counts_as_high_impact = FALSE,
  counts_as_neural = TRUE,
  counts_as_tissue_stress = TRUE,
  counts_as_conditioning = FALSE
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'pivot-to-sprint-start';

UPDATE coaching.exercise_safety_profile s SET
  risk_level = 2,
  impact_level = 1,
  requires_spotting = FALSE,
  requires_coach_supervision = 'optional_to_recommended',
  readiness_checks = ARRAY['Athlete can rotate through pain-free range without pinching or guarding.', 'Athlete can brace and breathe without breath holding or rib flare.', 'Athlete understands the start, finish, reset, and stop command.', 'Athlete is fresh enough for high-speed power or COD quality.', 'Landing, throwing, or cutting space is clear.']::text[],
  contraindications = ARRAY['Current spine, hip, shoulder, knee, or ankle pain aggravated by rotation.', 'Uncontrolled dizziness, balance loss, or symptoms during turning.', 'Inability to follow spacing, throw, landing, or stop commands.']::text[],
  common_substitutions = ARRAY['Standing rotational scoop toss', 'Static stance throw', 'Step-and-stick version', 'Lower-load medicine ball']::text[]
FROM coaching.exercise e
WHERE s.exercise_id = e.id AND e.slug = 'pivot-to-sprint-start';

