DELETE FROM coaching.exercise_tag t
USING coaching.exercise e
WHERE t.exercise_id = e.id
  AND e.slug IN ('9090-hip-switch-with-reach', 'half-kneeling-t-spine-rotation', 'spiderman-lunge-with-t-spine-reach', 'standing-hip-shoulder-separation-drill', 'wall-split-stance-rotation-reach', 'quadruped-thread-the-needle-reach', 'lateral-lunge-with-reach-across', 'cossack-shift-with-t-spine-reach', 'band-resisted-hip-turn-drill', 'low-intensity-carioca-grapevine', 'tall-kneeling-pallof-press', 'half-kneeling-pallof-press-iso-hold', 'split-stance-pallof-press', 'anti-rotation-cable-press-out', 'dead-bug-band-pulldown-with-rotation-resist', 'side-plank-row', 'side-plank-reach-through-control', 'bird-dog-band-row-anti-rotation', 'bear-position-shoulder-tap', 'suitcase-carry-march', 'landmine-rotation', 'landmine-rotational-press', 'half-kneeling-cable-lift', 'split-stance-cable-chop', 'rotational-cable-row', 'cable-shot-put-press', 'lateral-lunge-to-rotational-reach', 'loaded-cossack-squat', 'single-leg-rdl-airplane', 'suitcase-carry-with-direction-change', 'med-ball-rotational-scoop-toss', 'med-ball-shot-put-throw', 'med-ball-step-behind-rotational-throw', 'med-ball-shuffle-to-rotation-throw', 'med-ball-countermovement-rotational-throw', 'med-ball-slam-to-rotational-throw', 'half-kneeling-rotational-med-ball-throw', 'med-ball-overhead-to-side-slam', 'partner-rotational-scoop-toss', 'med-ball-rebound-rotational-catch-and-throw', 'carioca-build-up', 'crossover-run-drill', 'drop-step-crossover-go', '45-degree-cut-to-stick', 'reactive-45-degree-cut', 'lateral-bound-to-rotational-stick', '90-degree-hop-to-stick', '180-jump-to-stick', 'skater-bound-with-reach', 'pivot-to-sprint-start')
