UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('9090-hip-switch-with-reach', 'Use playful, slow, low-range reps for 90/90 Hip Switch with Reach; stop before the athlete turns mobility or sequencing into a race.', 'No default gender-specific adjustment. Scale by symptoms, training age, body size, rotation history, pelvic-floor or abdominal pressure symptoms, sport demand, and current readiness.'),
