UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'teen' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('9090-hip-switch-with-reach', 'Use 90/90 Hip Switch with Reach as part of a rotational development progression. Keep quality higher than volume and avoid fatigue-based twisting.', 'No default gender-specific adjustment. Scale by symptoms, training age, body size, rotation history, pelvic-floor or abdominal pressure symptoms, sport demand, and current readiness.'),
  ('half-kneeling-t-spine-rotation', 'Use Half-Kneeling T-Spine Rotation as part of a rotational development progression. Keep quality higher than volume and avoid fatigue-based twisting.', 'No default gender-specific adjustment. Scale by symptoms, training age, body size, rotation history, pelvic-floor or abdominal pressure symptoms, sport demand, and current readiness.'),
