-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  COALESCE(v.transfer, 'Develops hip-to-trunk-to-shoulder force transfer, rotational control, and spine-sparing rotation quality for throwing, swinging, striking, and cutting athletes.'),
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('9090-hip-switch-with-reach', 'Gives rotational athletes usable hip rotation and trunk reach without speed, load, or fatigue. Access drills work because they reduce positional restriction and improve the athlete''s ability to rotate through the right joints before adding intensity.', 'Gives rotational athletes usable hip rotation and trunk reach without speed, load, or fatigue.', 'Belongs in Prepare & Access because it creates rotational range, activation, and readiness without meaningful fatigue.', 'Use after a brief temperature raise and before Movement Intelligence, Output, Capacity, or sport skill work.', 'Turning rotational access work into forced end-range stretching, speed work, or extra fatigue before the athlete owns clean range.', 'Progress by range, rhythm, stance, or sport-specific angle. Regress to smaller range, slower tempo, more support, and fewer coordination demands.'),
  ('half-kneeling-t-spine-rotation', 'Separates upper-back rotation from lumbar twisting and gives throwers/swingers a clean trunk-rotation reference. Access drills work because they reduce positional restriction and improve the athlete''s ability to rotate through the right joints before adding intensity.', 'Separates upper-back rotation from lumbar twisting and gives throwers/swingers a clean trunk-rotation reference.', 'Belongs in Prepare & Access because it creates rotational range, activation, and readiness without meaningful fatigue.', 'Use after a brief temperature raise and before Movement Intelligence, Output, Capacity, or sport skill work.', 'Turning rotational access work into forced end-range stretching, speed work, or extra fatigue before the athlete owns clean range.', 'Progress by range, rhythm, stance, or sport-specific angle. Regress to smaller range, slower tempo, more support, and fewer coordination demands.'),
  ('spiderman-lunge-with-t-spine-reach', 'Combines hip extension, adductor access, trunk rotation, and shoulder reach in a pattern that transfers to throwing and cutting positions. Access drills work because they reduce positional restriction and improve the athlete''s ability to rotate through the right joints before adding intensity.', 'Combines hip extension, adductor access, trunk rotation, and shoulder reach in a pattern that transfers to throwing and cutting positions.', 'Belongs in Prepare & Access because it creates rotational range, activation, and readiness without meaningful fatigue.', 'Use after a brief temperature raise and before Movement Intelligence, Output, Capacity, or sport skill work.', 'Turning rotational access work into forced end-range stretching, speed work, or extra fatigue before the athlete owns clean range.', 'Progress by range, rhythm, stance, or sport-specific angle. Regress to smaller range, slower tempo, more support, and fewer coordination demands.'),
  ('standing-hip-shoulder-separation-drill', 'Teaches the athlete to initiate rotation from the ground and hips while the trunk stays organized instead of spinning as one stiff block. The drill improves timing and body map quality while the athlete is fresh, so later speed or power work has a cleaner movement answer.', 'Teaches the athlete to initiate rotation from the ground and hips while the trunk stays organized instead of spinning as one stiff block.', 'Belongs in Movement Intelligence because the main adaptation is coordination, rhythm, shape control, and movement literacy while fresh.', 'Use after warm-up while the nervous system is fresh, before high-intent Output, heavy strength, or conditioning.', 'Rushing reps, adding too many cues, or letting rhythm and posture break while pretending more chaos equals better athleticism.', 'Progress by range, rhythm, stance, or sport-specific angle. Regress to smaller range, slower tempo, more support, and fewer coordination demands.'),
  ('wall-split-stance-rotation-reach', 'Uses the wall to give a clear target for trunk reach while the lower body learns stable split-stance rotation. Access drills work because they reduce positional restriction and improve the athlete''s ability to rotate through the right joints before adding intensity.', 'Uses the wall to give a clear target for trunk reach while the lower body learns stable split-stance rotation.', 'Belongs in Prepare & Access because it creates rotational range, activation, and readiness without meaningful fatigue.', 'Use after a brief temperature raise and before Movement Intelligence, Output, Capacity, or sport skill work.', 'Turning rotational access work into forced end-range stretching, speed work, or extra fatigue before the athlete owns clean range.', 'Progress by range, rhythm, stance, or sport-specific angle. Regress to smaller range, slower tempo, more support, and fewer coordination demands.'),
  ('quadruped-thread-the-needle-reach', 'Low-threat floor drill that restores thoracic rotation and shoulder support without asking the athlete to rotate fast or load the spine. Access drills work because they reduce positional restriction and improve the athlete''s ability to rotate through the right joints before adding intensity.', 'Low-threat floor drill that restores thoracic rotation and shoulder support without asking the athlete to rotate fast or load the spine.', 'Belongs in Prepare & Access because it creates rotational range, activation, and readiness without meaningful fatigue.', 'Use after a brief temperature raise and before Movement Intelligence, Output, Capacity, or sport skill work.', 'Turning rotational access work into forced end-range stretching, speed work, or extra fatigue before the athlete owns clean range.', 'Progress by range, rhythm, stance, or sport-specific angle. Regress to smaller range, slower tempo, more support, and fewer coordination demands.'),
  ('lateral-lunge-with-reach-across', 'Connects lateral hip loading to trunk reach so rotational athletes can shift, coil, and own side-to-side positions. Access drills work because they reduce positional restriction and improve the athlete''s ability to rotate through the right joints before adding intensity.', 'Connects lateral hip loading to trunk reach so rotational athletes can shift, coil, and own side-to-side positions.', 'Belongs in Prepare & Access because it creates rotational range, activation, and readiness without meaningful fatigue.', 'Use after a brief temperature raise and before Movement Intelligence, Output, Capacity, or sport skill work.', 'Turning rotational access work into forced end-range stretching, speed work, or extra fatigue before the athlete owns clean range.', 'Progress by range, rhythm, stance, or sport-specific angle. Regress to smaller range, slower tempo, more support, and fewer coordination demands.'),
  ('cossack-shift-with-t-spine-reach', 'Builds usable side-to-side range for athletes who must rotate from wide or staggered bases. Access drills work because they reduce positional restriction and improve the athlete''s ability to rotate through the right joints before adding intensity.', 'Builds usable side-to-side range for athletes who must rotate from wide or staggered bases.', 'Belongs in Prepare & Access because it creates rotational range, activation, and readiness without meaningful fatigue.', 'Use after a brief temperature raise and before Movement Intelligence, Output, Capacity, or sport skill work.', 'Turning rotational access work into forced end-range stretching, speed work, or extra fatigue before the athlete owns clean range.', 'Progress by range, rhythm, stance, or sport-specific angle. Regress to smaller range, slower tempo, more support, and fewer coordination demands.'),
  ('band-resisted-hip-turn-drill', 'Light band tension teaches the athlete to turn from the hip and foot without yanking the torso around. Access drills work because they reduce positional restriction and improve the athlete''s ability to rotate through the right joints before adding intensity.', 'Light band tension teaches the athlete to turn from the hip and foot without yanking the torso around.', 'Belongs in Prepare & Access because it creates rotational range, activation, and readiness without meaningful fatigue.', 'Use after a brief temperature raise and before Movement Intelligence, Output, Capacity, or sport skill work.', 'Turning rotational access work into forced end-range stretching, speed work, or extra fatigue before the athlete owns clean range.', 'Progress by range, rhythm, stance, or sport-specific angle. Regress to smaller range, slower tempo, more support, and fewer coordination demands.'),
  ('low-intensity-carioca-grapevine', 'Introduces whole-body rotation, hip switching, and rhythm while keeping the drill warm-up level rather than conditioning. Access drills work because they reduce positional restriction and improve the athlete''s ability to rotate through the right joints before adding intensity.', 'Introduces whole-body rotation, hip switching, and rhythm while keeping the drill warm-up level rather than conditioning.', 'Belongs in Prepare & Access because it creates rotational range, activation, and readiness without meaningful fatigue.', 'Use after a brief temperature raise and before Movement Intelligence, Output, Capacity, or sport skill work.', 'Turning rotational access work into forced end-range stretching, speed work, or extra fatigue before the athlete owns clean range.', 'Progress by range, rhythm, stance, or sport-specific angle. Regress to smaller range, slower tempo, more support, and fewer coordination demands.'),
  ('tall-kneeling-pallof-press', 'Builds the trunk''s ability to resist rotation before the athlete tries to express rotation at speed. Rotational athletes need brakes as much as accelerators: anti-rotation, side support, and controlled bracing teach the body to absorb or redirect force before power work.', 'Builds the trunk''s ability to resist rotation before the athlete tries to express rotation at speed.', 'Belongs in Resilience because the main adaptation is trunk-pelvis control, braking, anti-rotation, joint ownership, and tissue durability.', 'Use after warm-up and often after the main strength or power work, or earlier at low dose when the goal is control activation.', 'Making anti-rotation or braking drills too heavy, too long, or too competitive so the athlete survives the set instead of controlling position.', 'Progress by torque, hold time, base challenge, perturbation, or reach length. Regress to shorter levers, more support, lighter tension, and slower reps.'),
  ('half-kneeling-pallof-press-iso-hold', 'The half-kneeling base exposes asymmetry and teaches rib-pelvis alignment under lateral rotational pull. Rotational athletes need brakes as much as accelerators: anti-rotation, side support, and controlled bracing teach the body to absorb or redirect force before power work.', 'The half-kneeling base exposes asymmetry and teaches rib-pelvis alignment under lateral rotational pull.', 'Belongs in Resilience because the main adaptation is trunk-pelvis control, braking, anti-rotation, joint ownership, and tissue durability.', 'Use after warm-up and often after the main strength or power work, or earlier at low dose when the goal is control activation.', 'Making anti-rotation or braking drills too heavy, too long, or too competitive so the athlete survives the set instead of controlling position.', 'Progress by torque, hold time, base challenge, perturbation, or reach length. Regress to shorter levers, more support, lighter tension, and slower reps.'),
  ('split-stance-pallof-press', 'Transfers bracing from the floor into a stance used for hitting, throwing, skating, and cutting. Rotational athletes need brakes as much as accelerators: anti-rotation, side support, and controlled bracing teach the body to absorb or redirect force before power work.', 'Transfers bracing from the floor into a stance used for hitting, throwing, skating, and cutting.', 'Belongs in Resilience because the main adaptation is trunk-pelvis control, braking, anti-rotation, joint ownership, and tissue durability.', 'Use after warm-up and often after the main strength or power work, or earlier at low dose when the goal is control activation.', 'Making anti-rotation or braking drills too heavy, too long, or too competitive so the athlete survives the set instead of controlling position.', 'Progress by torque, hold time, base challenge, perturbation, or reach length. Regress to shorter levers, more support, lighter tension, and slower reps.'),
  ('anti-rotation-cable-press-out', 'Longer lever press-out increases rotational torque while keeping the training goal control instead of maximal load. Rotational athletes need brakes as much as accelerators: anti-rotation, side support, and controlled bracing teach the body to absorb or redirect force before power work.', 'Longer lever press-out increases rotational torque while keeping the training goal control instead of maximal load.', 'Belongs in Resilience because the main adaptation is trunk-pelvis control, braking, anti-rotation, joint ownership, and tissue durability.', 'Use after warm-up and often after the main strength or power work, or earlier at low dose when the goal is control activation.', 'Making anti-rotation or braking drills too heavy, too long, or too competitive so the athlete survives the set instead of controlling position.', 'Progress by torque, hold time, base challenge, perturbation, or reach length. Regress to shorter levers, more support, lighter tension, and slower reps.'),
  ('dead-bug-band-pulldown-with-rotation-resist', 'Teaches the athlete to keep ribs and pelvis quiet while arms and legs create rotational and extension demands. Rotational athletes need brakes as much as accelerators: anti-rotation, side support, and controlled bracing teach the body to absorb or redirect force before power work.', 'Teaches the athlete to keep ribs and pelvis quiet while arms and legs create rotational and extension demands.', 'Belongs in Resilience because the main adaptation is trunk-pelvis control, braking, anti-rotation, joint ownership, and tissue durability.', 'Use after warm-up and often after the main strength or power work, or earlier at low dose when the goal is control activation.', 'Making anti-rotation or braking drills too heavy, too long, or too competitive so the athlete survives the set instead of controlling position.', 'Progress by torque, hold time, base challenge, perturbation, or reach length. Regress to shorter levers, more support, lighter tension, and slower reps.'),
